	('tZSKb_VwHHqFAIta7kDJE', 'Temple Cleaning Duty', 'https://utfs.io/f/Hzww9EQvYURJq8Cz9vdkOZgJQ8mGRcdx3SsWvPelyYFTt5Vn', '<p>Take on the task of cleaning the Temple of Susanoo in Shroud Village. Gather basic cleaning supplies from the village depot and proceed to the temple. Ensure all areas, including floors, walls, and statues, are thoroughly cleaned.</p>', 'Thanks for your services, the Kage is pleased.', 'D', '10', NULL, 'mission', '{\"reward\": {\"reward_exp\": 222, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 10000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 10, \"reward_prestige\": 10, \"reward_bloodlines\": [], \"reward_clanpoints\": 25}, \"objectives\": [{\"id\": \"h7ykpd85aMYCosnjNm42v\", \"task\": \"move_to_location\", \"image\": \"https://utfs.io/f/Hzww9EQvYURJq8Cz9vdkOZgJQ8mGRcdx3SsWvPelyYFTt5Vn\", \"sector\": 254, \"latitude\": 4, \"attackers\": [], \"completed\": 0, \"longitude\": 7, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"Pick up the cleaning tools.\", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": \"wto0Rro92SDh-r63K-iB4\", \"reward_prestige\": 0, \"sceneBackground\": \"\", \"sceneCharacters\": [], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"wto0Rro92SDh-r63K-iB4\", \"task\": \"move_to_location\", \"image\": \"https://utfs.io/f/Hzww9EQvYURJq8Cz9vdkOZgJQ8mGRcdx3SsWvPelyYFTt5Vn\", \"sector\": 254, \"latitude\": 11, \"attackers\": [], \"completed\": 0, \"longitude\": 10, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"Clean up the temple.\", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\":