	('7NC0adqxPbmweupbk4Wdv', 'The Lost Ninken', 'https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJVMpKpxF2veAXohUuE59nTQHRJIYjtiG18aF4', 'A young boy from the village, Kenta, is in tears. His new ninken (ninja hound) puppy, Maro, has eaten something that made him sick and has run off into the woods. Kenta is worried sick. Find Maro, figure out what\'s wrong with him, and bring him home safely.\n', 'You return to the village square with a happy, healthy Maro trotting by your side. Kenta runs up and gives his puppy a big hug. \"You saved him! Thank you, thank you!\"\n', 'D', '1', NULL, 'mission', '{\"reward\": {\"reward_exp\": 500, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 40000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 1000, \"reward_prestige\": 1000, \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 1000, \"reward_reputation\": 0, \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"reward_gathering_items\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 500, \"reward_crafting_experience\": 0, \"reward_gathering_experience\": 0}, \"objectives\": [{\"id\": \"oojAP\", \"task\": \"pvp_kills\", \"value\": 10, \"attackers\": [], \"reward_exp\": 0, \"description\": \"\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"reward_prestige\": 0, \"sceneBackground\": \"\", \"sceneCharacters\": [], \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"successDescription\": \"\", \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"attackers_scale_gains\": 1, \"reward_gathering_items\": false, \"attackers_max_per_battle\": 5, \"attackers_scaled_to_user\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_crafting_experience\": 0, \"reward_gathering_experience\": 0}], \"sceneBackground\": \"\", \"sc