	('XTJTFI5RTblRRaZBm5V8s', 'Enemy Recon', 'https://utfs.io/f/Hzww9EQvYURJmlDcCyHE4IMO5Goa7cgLxPJ0VC6lU8vbt1Ap', '<p>A foreign group of shinobi have been spotted on the outskirts of the village. Recon suggests they are gathering information to take back to an enemy village. While they are unknown, they must be stopped at all costs. Prepare yourself and follow them back to their encampment and dispatch then quietly. Be prepared for traps and possible reinforcements.</p>', '<p>Excellent job on dispatching the enemy. Take your reward and grab a hot bowl of ramen from the village.</p>', 'B', '25', NULL, 'mission', '{\"reward\": {\"reward_exp\": 670, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 25000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 150, \"reward_prestige\": 150, \"reward_bloodlines\": [], \"reward_clanpoints\": 150}, \"objectives\": [{\"id\": \"PM5ez2mOTQkEC3pRkqOxG\", \"task\": \"defeat_opponents\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJjcBYxV4XzPI8f1v96qBot0Q3wsUp2nxu7SMb\", \"sector\": 314, \"latitude\": 4, \"attackers\": [], \"completed\": 0, \"longitude\": 13, \"reward_exp\": 0, \"scaleGains\": 1, \"sectorList\": [], \"sectorType\": \"user_village\", \"description\": \"\", \"opponentAIs\": [{\"ids\": [\"d-t1xbnAoIZWEE2F8U8iS\"], \"number\": 1}], \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"drawDescription\": \"The battle ended in a draw\", \"failDescription\": \"You failed to defeat the opponent\", \"fleeDescription\": \"You fled from the opponent\", \"reward_prestige\": 0, \"sceneBackground\": \"\", \"sceneCharacters\": [], \"completionOutcome\": \"Win\", \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"opponent_scaled_to_user\": true, \"attackers_scaled_to_user\": false}], \"sceneB