	('WMQabX9bls80h0H-U8SCB', 'Penguin Rescue', 'https://utfs.io/f/Hzww9EQvYURJ0zki3WgrYldRWJcD6vE10SjNsXHeA9pVMfQi', '<p>Two penguins have become stuck in Glacier. Locate them and carefully help them get unstuck from narrow alleys or snowdrifts. Ensure they are unharmed and able to move freely. Complete the task to earn your reward.</p>', '<p>You have helped the penguins! They look so happy now.</p>', 'D', '3', NULL, 'mission', '{\"reward\": {\"reward_exp\": 222, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 10000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 10, \"reward_prestige\": 10, \"reward_bloodlines\": [], \"reward_clanpoints\": 25}, \"objectives\": [{\"id\": \"wyFZm6yJnNGowRfndZXcx\", \"task\": \"move_to_location\", \"image\": \"https://utfs.io/f/Hzww9EQvYURJ0zki3WgrYldRWJcD6vE10SjNsXHeA9pVMfQi\", \"sector\": 203, \"latitude\": 8, \"attackers\": [], \"completed\": 0, \"longitude\": 3, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"Help the penguin!\", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": \"AqsU5GTFdFICJdvN4Gpng\", \"reward_prestige\": 0, \"sceneBackground\": \"\", \"sceneCharacters\": [], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"AqsU5GTFdFICJdvN4Gpng\", \"task\": \"move_to_location\", \"image\": \"https://utfs.io/f/Hzww9EQvYURJ0zki3WgrYldRWJcD6vE10SjNsXHeA9pVMfQi\", \"sector\": 203, \"latitude\": 8, \"attackers\": [], \"completed\": 0, \"longitude\": 2, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"Help the penguin!\", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0,