VALUES
	('7681--humaaWlOtv8RqXr', 'Whispers Beneath the Temple – Part 2', 'https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJF0yIjFUG2iOewJtjGzvNcmEX3TBnoSfMDZPH', 'Lady Tohime, the Inari Priestess, vanished from her temple, leaving a trail of disturbing spiritual disruption. You\'ve confirmed she fled to Moonlight Lake, but the opposing chakra force pursuing her remains a mystery. The Seals of Sanctity are still intact—but for how long?\n\nHer trail leads east, into uncharted spiritual territory. The fate of the Inari Temple, and perhaps more, rests on finding her before the breach occurs\n', 'You prevented the Grand Seal from breaking and saved Lady Tohime...', 'D', '1', NULL, 'story', '{\"reward\": {\"reward_exp\": 10000, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 75000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 1000, \"reward_prestige\": 1000, \"reward_bloodlines\": [], \"reward_clanpoints\": 1000}, \"objectives\": [{\"id\": \"nEkgBsvRe7bp6IFuziwYo\", \"task\": \"move_to_location\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJF0yIjFUG2iOewJtjGzvNcmEX3TBnoSfMDZPH\", \"sector\": 10, \"latitude\": 6, \"attackers\": [], \"completed\": 0, \"longitude\": 7, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"\", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": \"1tue7MRSm5Al5hVWoAaHO\", \"reward_prestige\": 0, \"sceneBackground\": \"\", \"sceneCharacters\": [], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"1tue7MRSm5Al5hVWoAaHO\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"attackers\": [], \"reward_exp\": 0, \"description\": \"Tohime... she made it this far. Good. This charm, it\'s hers. And this... this opposing chakra you speak of... I\'ve felt it. A cold, alien presence. It\'s not of this land, not of our spiritual lineage. Her trail leads east, towards the Whispering Crags. A place steeped in old, forgotten energies. It must be where she sought to draw out her pursuers, or perhaps a place of hidden knowledge. You must follow her. Find her, warrior, before whatever pursues her succeeds in its aims. The sanctity of our temple, and the very balance of this region, depend on it.\\\"\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"Travel to the Whispering Crags\", \"nextObjectiveId\": \"sTg2whaKqTSyXIoBG9nzV\"}], \"reward_prestige\": 0, \"sceneBackground\": \"ZTlblQgoLfp7TEfzDWEiT\", \"sceneCharacters\": [\"iuSoj7nIUzlq0MsHYF9KK\"], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"sTg2whaKqTSyXIoBG9nzV\", \"task\": \"move_to_location\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJF0yIjFUG2iOewJtjGzvNcmEX3TBnoSfMDZPH\", \"sector\": 215, \"latitude\": 7, \"attackers\": [], \"completed\": 0, \"longitude\": 5, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"Travel to the Whispering Crags\", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": \"UUL9-OtV9G_dJ3A_FaNl2\", \"reward_prestige\": 0, \"sceneBackground\": \"\", \"sceneCharacters\": [], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"UUL9-OtV9G_dJ3A_FaNl2\", \"task\": \"dialog\", \"image\": \"http