	('-8gXrt8u0QzObW5v7I1QN', 'The Path of Greed', 'https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJAaFRe4hoZUC4muiGcQNzjfEndY5y1w20B8hT', 'To attain power, one must prove worthy. Defeat the master and claim the Keystone. ', 'Keystone attained. ', 'D', '50', NULL, 'story', '{\"reward\": {\"reward_exp\": 0, \"reward_rank\": \"NONE\", \"reward_items\": [{\"ids\": [\"HS430LRytJ3xK6fHlBjcF\"], \"number\": 100}], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 3000, \"reward_prestige\": 3000, \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 3000, \"reward_reputation\": 0, \"reward_seichi_silver\": 1, \"reward_medical_experience\": 250}, \"objectives\": [{\"id\": \"ZOis1\", \"task\": \"defeat_opponents\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJnA7z24mojJ0EqeDCvBrNmZaXVdY97gSpOWiA\", \"sector\": 222, \"latitude\": 5, \"attackers\": [], \"completed\": 0, \"longitude\": 5, \"reward_exp\": 0, \"scaleGains\": 1, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"Use Pierce, Heal reduction/prevention, Residuals and Drain to nullify passive healing. Burst when it\'s defense is down.\", \"opponentAIs\": [{\"ids\": [\"9sLd-qV82ktexu1HqkT1k\"], \"number\": 1}], \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"drawDescription\": \"The battle ended in a draw\", \"failDescription\": \"You failed to defeat the opponent\", \"fleeDescription\": \"You fled from the opponent\", \"reward_prestige\": 0, \"sceneBackground\": \"\", \"sceneCharacters\": [], \"completionOutcome\": \"Win\", \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"successDescription\": \"\", \"reward_seichi_silver\": 0, \"attackers_scale_gains\": 1, \"opponent_scaled_to_user\": false, \"attackers_scaled_to_user\": false, \"reward_medic