	('lsJOkaG2Q34ZdD2bQpYXa', 'Veins of the Serpent. ', 'https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJrBXCXnhuJPmdY8zI2ptZXAoEj1c6BMKvrQOx', 'A deep-earth mining site in Sector 15 has uncovered something ancient—and cursed. Miners began disappearing, only to return days later with glowing eyes and serpentine mutations. The Ouro Clan, masters of venom arts, are involved… but even they seem spooked. Uncover the truth and sever whatever is infecting the earth itself.', 'Good job!', 'A', '50', NULL, 'story', '{\"reward\": {\"reward_exp\": 10000, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 75000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 2000, \"reward_prestige\": 3000, \"reward_bloodlines\": [], \"reward_clanpoints\": 1000}, \"objectives\": [{\"id\": \"oXeHzhg6bOcwG0Gg0GRnY\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"attackers\": [], \"reward_exp\": 0, \"description\": \"Thank you for answering our summons. Our deep-earth mining site in Sector 15 has unearthed a curse we thought long buried. Miners began disappearing, only to return as... monsters. We sealed the lower levels years ago for a reason. Something has awakened. I need you to go to the Ironcoil Mines, find the source of this corruption, and sever it. The Ouro Clan will reward you handsomely.\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"I understand the risk, I will handle it\", \"nextObjectiveId\": \"K0XR8w6sAXRKidR_rbDw0\"}], \"reward_prestige\": 0, \"sceneBackground\": \"Bt0Y_p4y16xKHDe6oTuxT\", \"sceneCharacters\": [\"TCTNhtB8sb7WxWRh0laO2\"], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"K0XR8w6sAXRKidR_rbDw0\", \"task\": \"move_to_location\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJrBXCXnhuJPmdY8zI2ptZXAoEj1c6BMKvrQOx\", \"sector\": 15, \"latitude\": 8, \"attackers\": [], \"completed\": 0, \"longitude\": 14, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"Travel to the Ironcoil Mines to begin your investigation. \", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": \"dPStwzNRZjaFvdz_D5wdj\", \"reward_prestige\": 0, \"sceneBackground\": \"LfTMm_dQKGRCyMga31_r6\", \"sceneCharacters\": [], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"dPStwzNRZjaFvdz_D5wdj\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"sector\": 15, \"latitude\": 8, \"attackers\": [], \"longitude\": 14, \"reward_exp\": 0, \"description\": \"Dialog: As you step past the barricades into the mine\'s oppressive darkness, a scream echoes from the tunnels ahead. A figure stumbles into the light, his skin covered in shimmering scales. He hisses, \\\"She... awakens... below...\\\" before his eyes glaze over with green light and he lunges!\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"Defend yourself!\", \"nextObjectiveId\": \"2qIauqGqUo4W592DZhkpx\"}], \"reward_prestige\": 0, \"sceneBackground\": \"DBFjGpM0vTESF4DCfSkq5\", \"sceneCharacters\": [], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"2qIauqGqUo4W592DZhkpx\", \"task\": \"start_battle\", \"reward_exp\": 0, \"scaleGains\": 1, \"description\": \"\", \"opponent