 8, \"reward_exp\": 0, \"description\": \"With the thralls defeated, you notice a faint green glow from a nearby wall. A large, sharp fang is embedded in the rock, pulsing with a strange chakra.\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"Retrieve the glowing fang.\", \"nextObjectiveId\": \"wnCOp5EhwPVRisxqhsEXz\"}], \"reward_prestige\": 0, \"sceneBackground\": \"qFlPdSQgvUAxVyZv6A5Gy\", \"sceneCharacters\": [], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"wnCOp5EhwPVRisxqhsEXz\", \"task\": \"move_to_location\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJrBXCXnhuJPmdY8zI2ptZXAoEj1c6BMKvrQOx\", \"sector\": 15, \"latitude\": 6, \"attackers\": [], \"completed\": 0, \"longitude\": 11, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"\", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": \"oMXkmelydFa-792dn8czS\", \"reward_prestige\": 0, \"sceneBackground\": \"MYIT-aD5YFpp17v9F9Z4G\", \"sceneCharacters\": [], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}, {\"id\": \"oMXkmelydFa-792dn8czS\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"sector\": 15, \"latitude\": 6, \"attackers\": [], \"longitude\": 11, \"reward_exp\": 0, \"description\": \"As you grasp the fang, a sibilant whisper echoes directly into your mind: \'Follow the blood... deeper... where the true coil lies...\'\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0,