	('SFvrh0pQL0C_lsYvBgyXc', 'Round up the Babies', 'https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJALmdbgoZUC4muiGcQNzjfEndY5y1w20B8hTW', '<h1>🚨 EMERGENCY DISPATCH</h1>\n<h2>PRIORITY: D-CLASS THREAT (Potential to Escalate) — RECOVERY & CONTAINMENT</h2>\n<p><strong>ATTENTION:</strong> All <strong>Available Genins</strong></p>\n\n<h3>🛑 SUBJECT:</h3>\n<p><strong>Displaced Juvenile Fauna</strong></p>\n<p><strong>Designation:</strong> <span style=\"color:#888888;\">STONE SCALE WHELP</span></p>\n\n<h3>📍 LOCATION</h3>\n<p>\n  Last confirmed sighting in the <strong>farming outskirts of Sector 45</strong>, near the <em>old lumber mill</em>.<br>\n  Reports indicate it is <strong>frightened</strong> and <strong>seeking shelter</strong>.\n</p>\n\n<h3>🐾 VISUAL DESCRIPTION</h3>\n<ul>\n  <li><strong>Size:</strong> Roughly the size of a large boar or small calf.</li>\n  <li><strong>Movement:</strong> Clumsy and uncoordinated.</li>\n</ul>\n\n<p>Please proceed with <strong>care</strong>. Priority is <strong>non-lethal recovery and containment</strong>.</p>\n', 'Seichi is saved once more. ', 'D', '1', NULL, 'story', '{\"reward\": {\"reward_exp\": 25000, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 100000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 1000, \"reward_prestige\": 1000, \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 1000, \"reward_reputation\": 0, \"reward_hunter_items\": false, \"reward_seichi_silver\": 5, \"reward_gathering_items\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 300, \"reward_crafting_experience\": 0, \"reward_gathering_experience\": 0}, \"objectives\": [{\"id\": \"Zx2Br\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"attackers\": [], \"reward_exp\": 0, \"description\": \"EMERALD DRAGON.LOCATION: Last Confirmed visual contact over the Windswept Grasslands, . Currently moving slowly south towards t