	('qaMzIecpcr6MYls1qla72', 'The Tale of Goah Way: The Encounter on the Forest Trail', 'https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJzUEVDSemvaQu94EYJs8HpxVzofny6iPtbgCZ', 'While traveling with the wandering sun praiser, Goah Way, you discover an unconscious ninja from the Village of Silence. He\'s alive, but his story about being ambushed by a deer seems... odd. Goah intends to help, but the decision to get involved rests with you.', 'You helped Goah get the injured ninja, Sigi, to safety. After his recovery, you learned the slightly embarrassing truth of his accident and forged an unexpected but valuable alliance with a shinobi from the Village of Freedom State.', 'D', '1', NULL, 'story', '{\"reward\": {\"reward_exp\": 150, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 501, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"reward_prestige\": 5, \"reward_bloodlines\": [], \"reward_clanpoints\": 0}, \"objectives\": [{\"id\": \"VIDOr\", \"task\": \"pvp_kills\", \"value\": 10, \"attackers\": [], \"reward_exp\": 0, \"description\": \"\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"reward_prestige\": 0, \"sceneBackground\": \"\", \"sceneCharacters\": [], \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"successDescription\": \"\", \"attackers_scale_gains\": 1, \"attackers_scaled_to_user\": false}], \"sceneBackground\": \"\", \"sceneCharacters\": []}', '1', '2025-06-21 23:42:54.441', '2025-06-21 23:42:54.441', '2025-06-21', '1nSqxViGqnXp_xXAPeQMC', '1', '100', NULL, '1', '1', '2026-01-21', 'none', 'NONE', 'NONE', NULL),
	('R6y5XG-LVN_Tz-ZCRU3lB', 'Operation Silent Bell', 'https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJcu0XiNSnxBpQqGNDcTHbLmYz8uXAl3oa54ti', 'ANBU Command has issued a black-book mission. A former captain, codenamed \"Sparrow,\" has defected with critical intelligence regarding the village\'s entire informant network. You are to infiltrate the neutral port city of Kaiyo, locate him, and sanitize the asset and his knowledge before he compromises national security.', 'The target is eliminated, and his stolen memories are secured. You slip out of the city like a ghost, leaving no trace of your presence. The village\'s secrets are safe. Mission accomplished.', 'D', '1', NULL, 'anbu', '{\"reward\": {\"reward_exp\": 500, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 20000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 500, \"reward_prestige\": 1000, \"reward_anbupoints\": 100, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items_ids\": [], \"reward_gathering_experience\": 0}, \"objectives\": [{\"id\": \"s1Ptn\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"attackers\": [], \"reward_exp\": 0, \"description\": \"We have a ghost. \'Sparrow\' has fled with everything. His knowledge could burn our entire network to the ground. He has surfaced in the neutral port city of Kaiyo. Go there. Find him. Erase him and the memories he stole. Do not fail. Do not be seen. This is a Silent Bell operation\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"Accept Mission\", \"nextObjectiveId\": \"ZIR7M\"}], \"reward_prestige\": 0, \"sceneBackground\": \"4o9I_6ZUaVBhQHa3AxNbT\", \"sceneCharacters\": [\"0ZjvKlLeFfZxbU3Q6eLyQ\"], \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"successDescription\": \"\", \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"attackers_scale_gains\": 1, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"attackers_max_per_battle\": 5, \"attackers_scaled_to_user\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items_ids\": [], \"reward_gathering_experience\": 0}, {\"id\": \"ZIR7M\", \"task\": \"move_to_location\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJcu0XiNSnxBpQqGNDcTHbLmYz8uXAl3oa54ti\", \"sector\": 81, \"latitude\": 5, \"attackers\": [], \"completed\": 0, \"longitude\": 10, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"Travel to the neutral port city of Kaiyo and find a vantage point on the rooftops to begin your search.\", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": \"czKvz\", \"reward_prestige\": 0, \"sceneBackground\": \"ZSzoYrk49oaX3ard8GuP9\", \"sceneCharacters\": [], \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"successDescription\": \"\", \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"attackers_scale_gains\": 1, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"attackers_max_per_battle\": 5, \"attackers_scaled_to_user\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items_ids\": [], \"reward_gathering_experience\": 0}, {\"id\": \"czKvz\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"attackers\": [], \"reward_exp\": 0, \"description\": \"The city is a sprawling maze, but your training allows you to see what others miss. On a distant water tower, you spot a faint chakra seal—a directional marker from an old ANBU cipher. Sparrow is arrogant. He\'s using our own methods to lay his trail. \", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"Investigate the Trails\", \"nextObjectiveId\": \"F1gGP\"}], \"reward_prestige\": 0, \"sceneBackground\": \"ZSzoYrk49oaX3ard8GuP9\", \"sceneCharacters\": [], \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"successDescription\": \"\", \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"attackers_scale_gains\": 1, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"attackers_max_per_battle\": 5, \"attackers_scaled_to_user\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items_ids\": [], \"reward_gathering_experience\": 0}, {\"id\": \"F1gGP\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"attackers\": [], \"reward_exp\": 0, \"description\": \"The trail ends, pointing down towards a nondescript tea house in a shadowy alley. This is the place.\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"Infilitrate the Tea House\", \"nextObjectiveId\": \"fz43E\"}], \"reward_prestige\": 0, \"sceneBackground\": \"3zo3bAWvGmlxu4NT5vaGw\", \"sceneCharacters\": [], \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"successDescription\": \"\", \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"attackers_scale_gains\": 1, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"attackers_max_per_battle\": 5, \"attackers_scaled_to_user\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items_ids\": [], \"reward_gathering_experience\": 0}, {\"id\": \"fz43E\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"attackers\": [], \"reward_exp\": 0, \"description\": \"You slip inside. The air is still. You immediately spot three pressure plates, a nearly invisible tripwire connected to a poison dart trap, and a genjutsu seal on the main door designed to induce paranoia. You carefully disarm and navigate the traps, moving deeper into the building.\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"Attack Sparrow \", \"nextObjectiveId\": \"yo_G-\"}], \"reward_prestige\": 0, \"sceneBackground\": \"3zo3bAWvGmlxu4NT5vaGw\", \"sceneCharacters\": [], \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"successDescription\": \"\", \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"attackers_scale_gains\": 1, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"attackers_max_per_battle\": 5, \"attackers_scaled_to_user\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items