_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items_ids\": [], \"reward_gathering_experience\": 0}, {\"id\": \"R4pUY\", \"task\": \"fail_quest\", \"reward_exp\": 0, \"description\": \"Sparrow anticipated your move. You were detected by the city guard, forcing a chaotic retreat. The asset has escaped into the shadows, and the village\'s security is now critically compromised.\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"reward_prestige\": 0, \"sceneBackground\": \"4o9I_6ZUaVBhQHa3AxNbT\", \"sceneCharacters\": [], \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"successDescription\": \"\", \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items_ids\": [], \"reward_gathering_experience\": 0}], \"sceneBackground\": \"\", \"sceneCharacters\": []}', '0', '2025-07-20 16:57:41.794', '2025-07-20 16:57:41.794', NULL, NULL, '1', '100', NULL, '100', '100', NULL, 'none', 'NONE', 'NONE', NULL),
	('CwbKcxWOxZf9-TM358Hxz', 'Operation Rusting Serpent', 'https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJunQAeVtCyJLoOFkrcn4gxSwCfEQ9eMNXZlG8', 'ANBU Command has confirmed that the Land of Iron is transporting a shipment of newly developed \"Chakra-Jamming\" armor, a technology that could cripple shinobi forces. Your team\'s objective is to intercept the convoy in the treacherous Dragon\'s Tooth Pass and destroy the cargo, ensuring the attack looks like a natural disaster.\n', 'The convoy lies in ruins, buried under a perfectly executed rockslide. The chakra-jamming armor is destroyed, and no trace of your involvement remains. The Land of Iron will blame the mountain, not our village.\n', 'D', '1', NULL, 'anbu', '{\"reward\": {\"reward_exp\": 500, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 20000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 500, \"reward_prestige\": 1000, \"reward_anbupoints\": 100, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"reward_skillpoints\": 0, \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items_ids\": [], \"reward_gathering_experience\": 0}, \"objectives\": [{\"id\": \"ulW5m\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"attackers\": [], \"reward_exp\": 0, \"description\": \"The samurai have developed armor that makes ninjutsu useless. A convoy is moving a full shipment through Dragon\'s Tooth Pass in three days. Your mission is to ensure it never arrives. Destroy the cargo completely, and make it look like the mountain itself did the job. Leave no trace.\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"Mission Accepted\", \"nextObjectiveId\": \"CBLan\"}], \"reward_prestige\": 0, \"sceneBackground\": \"4o9I_6ZUaVBhQHa3AxNbT\", \"sceneCharacters\": [\"0ZjvKlLeFfZxbU3Q6eLyQ\"], \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"reward_skillpoints\": 0, \"successDescription\": \"\", \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"attackers_scale_gains\": 1, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"attackers_max_per_battle\": 5, \"attackers_scaled_to_user\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 0, \"reward_village_membership\": \"NONE\", \"reward_crafting_experience\": 0, \"reward_gathering_items_ids\": [], \"reward_gathering_experience\": 0}, {\"id\": \"CBLan\", \"task\": \"move_to_location\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJunQAeVtCyJLoOFkrcn4gxSwCfEQ9eMNXZlG8\", \"sector\": 34, \"latitude\": 5, \"attackers\": [], \"completed\": 0, \"longitude\": 7, \"reward_exp\": 0, \"sectorList\": [], \"sectorType\": \"specific\", \"description\": \"Travel to the ambush point in Dragon\'s Tooth Pass and survey the area.\", \"reward_rank\": \"NONE\", \"hideLocation\": false, \"locationType\": \"specific\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": \"zJ3w-\", \"reward_prestige\": 0, \"sceneBackground\": \"fsTSqblNesn0dNBgmPXHz\", \"sceneCharacters\": [], \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 0, \"reward_reputation\": 0, \"reward_skillpoints\": 0, \"successDescription\": \"\", \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"attackers_scale_gains\": 1, \"reward_gathering_items\": false, \"reward_hunter_items_ids\": [], \"attackers_max_per_battle\": 5, \"attackers_scaled_to_user\": false, \"reward_hunting_experience\": 0,