	('9NCb8FSTTvJUPq__MqwFa', 'The Silent Bloom', 'https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJeHzeq7yV3OvUJQExAi0bGoIZDF74LqSnHRdp', 'The secluded village of Verdant Hollow is afflicted by the \"Ashen Slumber,\" a mysterious condition where villagers fall into a deep, unwaking sleep. As a medical specialist, you must use your diagnostic and analytical skills to investigate the cause, deduce the necessary components for a cure, and synthesize an elixir before the slumber becomes permanent.\n', 'The elixir works. A wave of gentle energy washes over the village, and the sleeping residents begin to stir, awakening as if from a long dream. Your medical expertise and sharp investigative mind have saved Verdant Hollow.', 'D', '1', NULL, 'medical', '{\"reward\": {\"reward_exp\": 300, \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 100000, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 1000, \"reward_prestige\": 1000, \"reward_anbupoints\": 0, \"reward_bloodlines\": [], \"reward_clanpoints\": 1000, \"reward_reputation\": 0, \"reward_hunter_items\": false, \"reward_seichi_silver\": 0, \"reward_gathering_items\": false, \"reward_hunting_experience\": 0, \"reward_medical_experience\": 3000, \"reward_crafting_experience\": 0, \"reward_gathering_experience\": 0}, \"objectives\": [{\"id\": \"hbsHj\", \"task\": \"dialog\", \"image\": \"https://ui0arpl8sm.ufs.sh/f/Hzww9EQvYURJpIn7vsbKBAOsGCHyl3Sk0mZFrgWPUdjMJ75D\", \"attackers\": [], \"reward_exp\": 0, \"description\": \"Our people are falling into the Ashen Slumber. Our healers are baffled. Please, use your skills to diagnose this illness and find a cure. The fate of our village is in your hands.\", \"reward_rank\": \"NONE\", \"reward_items\": [], \"reward_money\": 0, \"reward_badges\": [], \"reward_jutsus\": [], \"reward_tokens\": 0, \"nextObjectiveId\": [{\"text\": \"Start Investigation\", \"nextObjectiveId\": \"IYWsa\"}], \"reward_prestige\": 0, \"sceneBackground\": \"DNOR4Qsm13emQyuOse-or\", \"sce